import redis
from rediscluster import RedisCluster

#Establishing Connection
startup_nodes = [{"host": "127.0.0.1", "port": "7000"}, {"host": "127.0.0.1", "port": "7001"}]
r = RedisCluster(startup_nodes=startup_nodes, decode_responses=True)

def cache_data(key, value, ttl):
    try:
        r.set(key, value) #Set data for a key
        r.expire(key, ttl) #Set TTL
        return "Successfully cached data"
    except Exception as e:
        return str(e)

def get_data(key):
    try:
        return r.get(key) #Get data for a key
    except Exception as e:
        return str(e)

def store_sensitive_data(user_id, session_token, api_key):
    try:
        #Storing Session Tokens and API Keys (TTL = 2 hours)
        cache_data(f"user:{user_id}:session_token", session_token, 7200)
        cache_data(f"user:{user_id}:api_key", api_key, 7200)
        return "Successfully stored sensitive data"
    except Exception as e:
        return str(e)